/**
 * v2.41.03 MEB-95 SBG: KEYASPECT dem SBFICODE zuweisbar machen
 * - Alter table SBG_KEYASPECT:
 *   - Use SBFICODE instead of PROFESSIONCODE
 *   - add new columns VALIDFROMYEAR/VALIDTOYEAR
  *  - add unique index
 * - Insert the new values
 */

ALTER TABLE SBG_KEYASPECT ADD SBFICODE NUMBER(5,0);
ALTER TABLE SBG_KEYASPECT ADD VALIDFROMYEAR NUMBER(4,0);
ALTER TABLE SBG_KEYASPECT ADD VALIDTOYEAR NUMBER(4,0);
ALTER TABLE SBG_KEYASPECT DROP COLUMN PROFESSIONCODE;

DELETE FROM SBG_KEYASPECT;

CREATE UNIQUE INDEX SBG_KEYASPECT_LOGICAL_KEY ON SBG_KEYASPECT (SBFICODE, KEYASPECTCODE, VALIDFROMYEAR) LOGGING TABLESPACE MEB_INDEX COMPUTE STATISTICS;
ALTER TABLE SBG_KEYASPECT ADD (CONSTRAINT SBG_KEYASPECT_LOGICAL_KEY UNIQUE (SBFICODE, KEYASPECTCODE, VALIDFROMYEAR) USING INDEX SBG_KEYASPECT_LOGICAL_KEY ENABLE VALIDATE);

